import { useState, useEffect } from 'react';
import { StellarWalletsKit, WalletNetwork, allowAllModules } from '@creit.tech/stellar-wallets-kit';

// Initialize the kit globally so it can be reused
const kit = new StellarWalletsKit({
  network: WalletNetwork.TESTNET,
  selectedWalletId: 'freighter',
  modules: allowAllModules(),
});

export function useStellarWallet() {
  const [address, setAddress] = useState(null);
  const [error, setError] = useState(null);
  const [isConnecting, setIsConnecting] = useState(false);

  // Check if already connected on mount
  useEffect(() => {
    // Some wallets might inject or store session
    // We can just leave it to explicit connect for now
  }, []);

  const connect = async () => {
    setIsConnecting(true);
    setError(null);
    try {
      await kit.openModal({
        onWalletSelected: async (option) => {
          kit.setWallet(option.id);
          const { address } = await kit.getAddress();
          setAddress(address);
        }
      });
    } catch (err) {
      console.error(err);
      if (err.message && err.message.includes('User declined')) {
         setError('User rejected the connection request.');
      } else if (err.message && err.message.includes('not installed')) {
         setError('Wallet not found. Please install a Stellar wallet like Freighter.');
      } else {
         setError('Failed to connect wallet: ' + err.message);
      }
    } finally {
      setIsConnecting(false);
    }
  };

  const disconnect = () => {
    setAddress(null);
  };

  const signTransaction = async (xdr) => {
    try {
      const result = await kit.signTx({ xdr, publicKeys: [address], network: WalletNetwork.TESTNET });
      return result.signedTxXdr;
    } catch (err) {
      if (err.message && err.message.includes('User declined')) {
        throw new Error('User rejected the transaction.');
      }
      throw err;
    }
  };

  return {
    address,
    error,
    isConnecting,
    connect,
    disconnect,
    signTransaction
  };
}
